import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { link } from 'decantr/router';
import { Button, icon, Badge } from 'decantr/components';

code.example:
function UnitList({ propertyId, units }) {
  const { div, h2, span } = tags;
  const [filter, setFilter] = createSignal('all');

  const filtered = () => filter() === 'all' ? units : units.filter(u => u.status === filter());
  const occupied = units.filter(u => u.status === 'occupied').length;
  const vacant = units.filter(u => u.status === 'vacant').length;
  const totalRent = units.reduce((sum, u) => sum + (u.status === 'occupied' ? u.rent : 0), 0);

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _jcsb _aic') },
      h2({ class: css('_heading4') }, 'Units'),
      Button({ variant: 'primary', size: 'sm' }, icon('plus'), 'Add Unit')
    ),
    div({ class: css('_flex _gap4 _aic') },
      div({ class: css('_flex _gap1') },
        Button({ variant: filter() === 'all' ? 'default' : 'ghost', size: 'sm', onclick: () => setFilter('all') }, `All (${units.length})`),
        Button({ variant: filter() === 'occupied' ? 'default' : 'ghost', size: 'sm', onclick: () => setFilter('occupied') }, `Occupied (${occupied})`),
        Button({ variant: filter() === 'vacant' ? 'default' : 'ghost', size: 'sm', onclick: () => setFilter('vacant') }, `Vacant (${vacant})`)
      ),
      span({ class: css('_ml[auto] _textsm _fgmuted') }, `Total Rent: $${totalRent.toLocaleString()}/mo`)
    ),
    div({ class: css('_grid _cols3 _gap4') },
      ...filtered().map(unit => UnitCard({ propertyId, unit }))
    )
  );
}

function UnitCard({ propertyId, unit }) {
  const { div, span, p } = tags;
  const statusColor = unit.status === 'occupied' ? 'success' : 'danger';

  return link({ href: `/properties/${propertyId}/units/${unit.id}`, class: css('estate-card _p4 _flex _col _gap3 _trans _hoverShadow') },
    div({ class: css('_flex _jcsb _aic') },
      span({ class: css('_heading5') }, `Unit ${unit.number}`),
      Badge({ variant: statusColor }, unit.status)
    ),
    div({ class: css('_flex _gap4 _textsm _fgmuted') },
      span({}, `${unit.beds} bed`),
      span({}, `${unit.baths} bath`),
      span({}, `${unit.sqft} sqft`)
    ),
    unit.tenant ? div({ class: css('_pt3 _borderT') },
      p({ class: css('_textsm _font500') }, unit.tenant.name),
      p({ class: css('_textxs _fgmuted') }, `Lease ends ${unit.leaseEnd}`)
    ) : div({ class: css('_pt3 _borderT _fgmuted _textsm') }, 'Vacant'),
    div({ class: css('_flex _jcsb _aic _pt2') },
      span({ class: css('_heading6') }, `$${unit.rent.toLocaleString()}/mo`),
      Button({ variant: 'ghost', size: 'sm' }, icon('chevron-right'))
    )
  );
}

