function UnitTable({ propertyId, units }) {
  const { div, table, thead, tbody, tr, th, td, span } = tags;

  return div({ class: css('estate-table _overflow[auto]') },
    table({ class: css('_wfull') },
      thead({},
        tr({ class: css('_bgSurface') },
          th({ class: css('_p3 _textleft _font500') }, 'Unit'),
          th({ class: css('_p3 _textleft _font500') }, 'Specs'),
          th({ class: css('_p3 _textleft _font500') }, 'Tenant'),
          th({ class: css('_p3 _tr _font500') }, 'Rent'),
          th({ class: css('_p3 _textleft _font500') }, 'Lease End'),
          th({ class: css('_p3 _tc _font500') }, 'Status'),
          th({ class: css('_p3') })
        )
      ),
      tbody({},
        ...units.map((u, i) =>
          tr({ class: css(i % 2 === 0 ? '' : '_bgSurfaceRaised') },
            td({ class: css('_p3 _font500') }, `Unit ${u.number}`),
            td({ class: css('_p3 _textsm _fgmuted') }, `${u.beds}bd / ${u.baths}ba / ${u.sqft}sf`),
            td({ class: css('_p3') }, u.tenant ? u.tenant.name : span({ class: css('_fgmuted') }, '—')),
            td({ class: css('_p3 _tr _font500') }, `$${u.rent.toLocaleString()}`),
            td({ class: css('_p3 _textsm') }, u.leaseEnd || '—'),
            td({ class: css('_p3 _tc') }, Badge({ variant: u.status === 'occupied' ? 'success' : 'danger' }, u.status)),
            td({ class: css('_p3') },
              link({ href: `/properties/${propertyId}/units/${u.id}` },
                Button({ variant: 'ghost', size: 'sm' }, icon('chevron-right'))
              )
            )
          )
        )
      )
    )
  );
}

